import React, { useState, useMemo, useEffect } from 'react';
import { api } from '../services/api';
import { BotMessageSquareIcon, UsersIcon, LoaderCircleIcon, CheckIcon } from '../components/Icons';
import { PasswordInput } from '../components/PasswordInput';
import { PasswordStrength } from '../components/PasswordStrength';

type AuthMode = 'signIn' | 'signUp' | 'forgotPassword' | 'awaitingConfirmation';

interface LoginPageProps {
    onShowPrivacy: () => void;
}

export const LoginPage: React.FC<LoginPageProps> = ({ onShowPrivacy }) => {
    const [mode, setMode] = useState<AuthMode>('signIn');
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const [successMessage, setSuccessMessage] = useState('');
    const [hasInvite, setHasInvite] = useState(false);

    useEffect(() => {
        if (localStorage.getItem('project_invite_token')) {
            setHasInvite(true);
        }
    }, []);

    const passwordChecks = useMemo(() => ({
        length: password.length >= 8,
        uppercase: /[A-Z]/.test(password),
        lowercase: /[a-z]/.test(password),
        number: /[0-9]/.test(password),
        specialChar: /[^A-Za-z0-9]/.test(password),
    }), [password]);

    const isPasswordValid = Object.values(passwordChecks).every(Boolean);

    const handleResendConfirmation = async () => {
        if (!email) {
            setError('Please enter your email address to resend the confirmation link.');
            return;
        }
        setLoading(true);
        setError('');
        setSuccessMessage('');

        const { error } = await api.auth.resendConfirmationEmail(email);

        if (error) {
            setError(error.message);
        } else {
            setSuccessMessage('A new confirmation link has been sent to your email.');
        }
        setLoading(false);
    };

    const navigateToSignup = (msg: string) => {
        setError(msg);
        setTimeout(() => {
            setError('');
            setMode('signUp');
        }, 2500);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        setSuccessMessage('');

        if (mode === 'forgotPassword') {
            const { error } = await api.auth.sendPasswordResetEmail(email);
            if (error) {
                const msg = error.message.toLowerCase();
                // "Error sending recovery email" is Supabase's generic failure string
                if (msg.includes('user not found') || msg.includes('not registered')) {
                    navigateToSignup('Account not found. Redirecting to Sign Up...');
                } else if (msg.includes('rate limit') || msg.includes('too many requests')) {
                    setError('Too many attempts. Please wait 15-60 minutes before trying again.');
                } else if (msg.includes('error sending recovery email')) {
                    setError('Recovery failed. Please ensure the email is correct or try again in an hour (rate limit).');
                } else if (msg.includes('network') || msg.includes('fetch')) {
                    setError('Network error. Please check your connection and try again.');
                } else {
                    setError(error.message);
                }
            } else {
                setSuccessMessage("If an account exists for this email, a reset link has been sent!");
            }
        } else if (mode === 'signIn') {
            const { error } = await api.auth.signInWithPassword({ email, password });
            if (error) {
                const msg = error.message.toLowerCase();
                if (msg.includes('email not confirmed')) {
                    setMode('awaitingConfirmation');
                    setSuccessMessage('');
                    setError('');
                } else if (msg.includes('invalid login credentials') || msg.includes('user not found') || msg.includes('not registered')) {
                    navigateToSignup('Account not found. Redirecting to Sign Up...');
                } else {
                    setError(error.message);
                }
            }
        } else { // signUp
            if (!isPasswordValid) {
                setError("Please ensure your password meets all requirements.");
                setLoading(false);
                return;
            }
            const { error } = await api.auth.signUp({ email, password, name });
            if (error) {
                setError(error.message);
            } else {
                setSuccessMessage(`A confirmation link has been sent to ${email}.`);
                setMode('awaitingConfirmation');
            }
        }

        setLoading(false);
    };

    const handleModeChange = (newMode: AuthMode) => {
        setMode(newMode);
        setError('');
        setSuccessMessage('');
        setName('');
        setPassword('');
    };

    if (mode === 'awaitingConfirmation') {
        return (
            <div className="text-center">
                <div className="flex flex-col items-center mb-6">
                    <div className="relative mb-6">
                        <BotMessageSquareIcon className="w-16 h-16 text-gray-400" />
                        <div className="absolute -bottom-2 -right-2 bg-green-500 rounded-full p-1 border-2 border-[#131C1B]">
                            <CheckIcon className="w-5 h-5 text-white" />
                        </div>
                    </div>
                    <h1 className="text-xl font-bold tracking-tight text-white mt-2">
                        Check your email
                    </h1>
                </div>
                <div className="space-y-4">
