                    >
                        {loading ? <LoaderCircleIcon className="animate-spin h-5 w-5" /> : 'Resend confirmation link'}
                    </button>

                    <button onClick={() => handleModeChange('signIn')} className="text-xs font-medium text-white hover:text-gray-300">
