    const { data: userProfile, error } = await supabase
        .from('users')
        .select('*')
        .eq('id', userId)
        .single();
    if (error && error.code !== 'PGRST116') { 
        console.error("Error fetching user profile:", error.message || error);
        throw error; 
    }
    return userProfile as User;
};

