export const generateTasksFromFile = async (fileData: { content: string; mimeType: string }, columnNames: string[], headersToInclude: string[]): Promise<AiGeneratedTaskFromFile[]> => {
    try {
        const isTextFile = fileData.mimeType.startsWith('text/') || fileData.mimeType === 'application/json';
        const promptText = `Parse this file into tasks JSON. Allowed statuses: ${columnNames.join(',')}. Include headers: ${headersToInclude.join(',')}.`;

        let contents;
        if (isTextFile) {
            contents = `${promptText}\n\nFile Content:\n${truncateContent(fileData.content)}`;
        } else {
            // For binary files, use inlineData part, but Gemini has strict size limits
            // If data is too large, it must be truncated before encoding to base64, which is tricky
            // We'll rely on the API error handling for now but ensure we aren't sending massive base64 strings if possible.
            contents = { parts: [
                { text: promptText },
                { inlineData: { mimeType: fileData.mimeType, data: fileData.content } }
            ]};
        }

        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: contents,
            config: {
                responseMimeType: "application/json",
                responseSchema: tasksFromFileResponseSchema,
            },
        });

        return JSON.parse(response.text.trim()) as AiGeneratedTaskFromFile[];
    } catch (error) {
        handleApiError(error, 'parse tasks from file');
        return [];
    }
};

