    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: `Extract bugs from content (headers: ${headers.join(',')}): ${truncateContent(fileContent)}`,
            config: { responseMimeType: "application/json" },
        });
        return JSON.parse(response.text || "[]");
    } catch (error) {
        handleApiError(error, 'parse bugs');
        return [];
    }
};

export const generateTasksFromFile = async (fileData: { content: string; mimeType: string }, columnNames: string[], headers: string[]): Promise<AiGeneratedTaskFromFile[]> => {
    try {
        const isText = fileData.mimeType.startsWith('text/') || fileData.mimeType === 'application/json';
        const instruction = `Analyze file and extract JSON tasks. Allowed columns: ${columnNames.join(',')}. Headers: ${headers.join(',')}.`;

        let contents;
        if (isText) {
            // Fix: Truncate large text and pass as string
            contents = `${instruction}\n\nContent:\n${truncateContent(fileData.content)}`;
        } else {
            // Fix: Properly use the multi-part structure for binary data to avoid [object Object] error
            contents = { parts: [
                { text: instruction },
                { inlineData: { mimeType: fileData.mimeType, data: fileData.content } }
            ]};
        }

        const response = await ai.models.generateContent({
            model: "gemini-3-pro-preview",
            contents: contents,
            config: {
                responseMimeType: "application/json",
                responseSchema: tasksFromFileResponseSchema,
            },
        });

        return JSON.parse(response.text || "[]");
    } catch (error) {
        handleApiError(error, 'parse tasks from file');
        return [];
    }
};

